#include <bits/stdc++.h>
using namespace std;
struct Node{
    int s,con;
};
int n,t,k,x,sum[100005],cnt;
queue<Node> q;
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d",&t,&k);
        while(k--){
            scanf("%d",&x);
            q.push({t,x});
            if(!sum[x]++)
                cnt++;
        }
        while(q.size() && q.front().s<=t-86400){
            if(!--sum[q.front().con])
                cnt--;
            q.pop();
        }
        printf("%d\n",cnt);
    }
    return 0;
}
